'use client';
import { useEffect, useRef, useState } from "react";
import gsap from "gsap";

const ThemeSwitcher = () => {
  const themeSwitcherRef = useRef<HTMLDivElement>(null);
  const [isDark, setIsDark] = useState(true);

  useEffect(() => {
    gsap.to(themeSwitcherRef.current, {
      opacity: 1,
      duration: 1,
      delay: 1,
    });
  }, []);

  const toggleTheme = () => {
    setIsDark(!isDark);
    document.documentElement.classList.toggle('light-theme', isDark);
    const metaThemeColor = document.querySelector('meta[name="theme-color"]');
    if (metaThemeColor) {
      metaThemeColor.setAttribute('content', isDark ? '#ffffff' : '#0a0a0a');
    }
  };

  return (
    <div className="fixed top-6 right-6" ref={themeSwitcherRef} style={{ opacity: 0, zIndex: 10 }}>
      <button 
        className="w-10 h-10 rounded-full bg-white/10 backdrop-blur-md border border-white/20 flex items-center justify-center hover:bg-white/20 transition-all text-white shadow-lg"
        onClick={toggleTheme}
        aria-label="Toggle Theme"
      >
        {/* @ts-ignore */}
        <ion-icon name={isDark ? "sunny-outline" : "moon-outline"} style={{ fontSize: "1.2rem" }}></ion-icon>
      </button>
    </div>
  );
};

export default ThemeSwitcher;